import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";const i=JSON.parse(`{"title":"Perguntas frequentes dos jogadores","description":"Dúvidas mais frequentes dos jogadores e administradores de servidor sobre o Fabric.","frontmatter":{"title":"Perguntas frequentes dos jogadores","description":"Dúvidas mais frequentes dos jogadores e administradores de servidor sobre o Fabric.","search":false,"files":[]},"headers":[],"relativePath":"pt_br/1.20.4/players/faq.md","filePath":"versions/1.20.4/translated/pt_br/players/faq.md","lastUpdated":1739538073000}`);var a={name:`pt_br/1.20.4/players/faq.md`};function o(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Perguntas frequentes dos jogadores <a class="header-anchor" href="#h1" aria-label="Permalink to “Perguntas frequentes dos jogadores”">​</a></h1><p>Há muitas perguntas feitas com frequência, então compilamos uma lista delas aqui.</p><h2 id="perguntas-gerais" tabindex="-1">Perguntas Gerais <a class="header-anchor" href="#perguntas-gerais" aria-label="Permalink to “Perguntas Gerais”">​</a></h2><h3 id="quais-versoes-do-minecraft-o-fabric-e-compativel" tabindex="-1">Quais versões do Minecraft o Fabric é compatível? <a class="header-anchor" href="#quais-versoes-do-minecraft-o-fabric-e-compativel" aria-label="Permalink to “Quais versões do Minecraft o Fabric é compatível?”">​</a></h3><p>Oficialmente, o Fabric é compatível com todas as versões do Minecraft começando da snapshot <code>18w43b</code> em diante, e versões da <code>1.14</code> em diante.</p><h3 id="onde-eu-posso-baixar-mods-publicados-do-fabric" tabindex="-1">Onde eu posso baixar mods publicados do Fabric? <a class="header-anchor" href="#onde-eu-posso-baixar-mods-publicados-do-fabric" aria-label="Permalink to “Onde eu posso baixar mods publicados do Fabric?”">​</a></h3><div class="info custom-block"><p class="custom-block-title custom-block-title-default">INFO</p><p>Você deve sempre verificar se os mods são de fontes confiáveis. Visite o guia <a href="./finding-mods">Encontrando Mods Confiáveis</a> para mais informações.</p></div><p>A maioria dos autores publicam seus mods no <a href="https://modrinth.com/mods?g=categories:%27fabric%27" target="_blank" rel="noreferrer">Modrinth</a> e no <a href="https://www.curseforge.com/minecraft/search?class=mc-mods&amp;gameVersionTypeId=4" target="_blank" rel="noreferrer">CurseForge</a>, no entando, alguns preferem publicá-los em seus sites pessoais, ou em outras plataformas, como um repositório GitHub.</p><h3 id="onde-eu-posso-achar-modpacks-para-fabric-pre-feitos" tabindex="-1">Onde eu posso achar modpacks para Fabric pré-feitos? <a class="header-anchor" href="#onde-eu-posso-achar-modpacks-para-fabric-pre-feitos" aria-label="Permalink to “Onde eu posso achar modpacks para Fabric pré-feitos?”">​</a></h3><p>Você pode achar modpacks para Fabric pré-feitos em várias plataformas, como:</p><ul><li><a href="https://modrinth.com/modpacks?g=categories:%27fabric%27" target="_blank" rel="noreferrer">Modrinth</a></li><li><a href="https://www.curseforge.com/minecraft/search?class=modpacks&amp;gameVersionTypeId=4" target="_blank" rel="noreferrer">CurseForge</a></li><li><a href="https://www.feed-the-beast.com/ftb-app" target="_blank" rel="noreferrer">Feed The Beast</a></li><li><a href="https://www.technicpack.net/modpacks" target="_blank" rel="noreferrer">Technic</a></li></ul>`,11)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};